async function sendDailyDigest() {
  logger.info("Running daily digest job");
  const today = istDateStr();
  const users = await db.select().from(usersTable);
  let sent = 0;
  let eligible = 0;
  let skippedNoEmail = 0;
  let failedSend = 0;
  for (const user of users) {
    const tasks2 = await db.select().from(tasksTable).where(and(eq(tasksTable.assignedTo, user.id), ne(tasksTable.status, "done")));
    const relevant = tasks2.filter((t) => t.dueDate && t.dueDate <= today);
    if (!relevant.length) continue;
    eligible++;
    if (!user.email) {
      skippedNoEmail++;
      continue;
    }
    const ok = await sendDailyDigestEmail({
      toEmail: user.email,
      toName: user.name,
      dateStr: today,
      tasks: relevant.map((t) => ({
        title: t.title,
        status: t.status,
        priority: t.priority,
        type: t.type,
        dueDate: t.dueDate,
        overdue: !!t.dueDate && t.dueDate < today
      })).sort((a, b) => Number(b.overdue) - Number(a.overdue))
    });
    if (ok) sent++;
    else failedSend++;
    await new Promise((r) => setTimeout(r, 600));
  }
  logger.info({ sent, eligible, skippedNoEmail, failedSend }, "Daily digest complete");
  return { sent, eligible, skippedNoEmail, failedSend };
}
